class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def _build(values):
    head = None
    for v in reversed(values):
        head = ListNode(v, head)
    return head

def _to_list(head):
    out = []
    while head:
        out.append(head.val)
        head = head.next
    return out

